SourceCode.Declaration:
/// <summary>
/// Extension for InventJournalTable datasource on InventJournalMovement form.
/// Disables editing and modification when the journal is linked
/// to an FG Movement Journal.
/// </summary>
[ExtensionOf(formDataSourceStr(InventJournalMovement, InventJournalTable))]
final class ETGInventJournalMovement_Table_DS_Extension
{
}

Method.Source:
public int active()
{
    int ret=next active();


    if(ETGCanadaParameters::find().EnableAutoMovementJournalCreation == NoYes::Yes)
    {
        InventJournalTable journalTable = this.cursor();
        InventJournalTrans journalTrans;
        FormDataSource formDataSource  = this.formRun().datasource(formDataSourcestr(InventJournalMovement,InventJournalTrans));
        FormDataSource formDataSource1 = this.formRun().datasource(formDataSourcestr(InventJournalMovement,InventJournalTable));
        FormDataSource formDataSource2 = this.formRun().datasource(formDataSourcestr(InventJournalMovement,InventDim));
        FormDataSource formDataSource3 = this.formRun().datasource(formDataSourcestr(InventJournalMovement,InventJournalTransTaxExtensionIN));
        FormControl editButton         = this.formRun().design().controlName("SystemDefinedViewEditButton");

        select firstOnly journalTrans
        where journalTrans.ETGFGMovementJournalId == journalTable.JournalId;


        if (journalTrans)
        {
            formDataSource.allowEdit(false);
            formDataSource.allowCreate(false);
            formDataSource.allowDelete(false);
            formDataSource1.allowEdit(false);
            formDataSource2.allowEdit(false);
            formDataSource3.allowEdit(false);
            editButton.enabled(false);
        }
    }

    return ret;

}
